import { eq, inArray } from "drizzle-orm";
import { v4 } from "uuid";
import { test as base, expect } from "vitest";
import { fetchServiceNoteData } from "./fetch-service-note-data";

interface TestData {
  targetCustomer: {
    customerId: string;
    firstName: string;
    lastName: string;
    birthDate: string;
    gender: number;
    remarks: string;
