      {
        customerId: otherCustomerId,
        email: `other-${v4()}@example.com`,
        firstName: "花子",
        lastName: "他顧客",
        phone: "09087654321",
      },
    ]);

    const targetNotes: TestData["targetNotes"] = [
      {
        content: "対象顧客ノート1",
        customerNoteId: v4(),
        serviceDate: "2024-01-01",
      },
      {
        content: "対象顧客ノート2",
        customerNoteId: v4(),
        serviceDate: "2024-01-02",
      },
      {
        content: "対象顧客ノート3",
        customerNoteId: v4(),
        serviceDate: "2024-01-03",
      },
      {
        content: "対象顧客ノート4",
        customerNoteId: v4(),
        serviceDate: "2024-01-04",
      },
      {
        content: "対象顧客ノート5",
        customerNoteId: v4(),
        serviceDate: "2024-01-05",
